/**
 * @param {number[]} nums
 * @param {number} target
 * @return {number}
 */
function solve(nums, target) {
    const n = nums.length;
    let minRemovals = Infinity;

    // The problem asks for the minimum number of removals such that the XOR sum of the remaining elements equals target.
    // This is equivalent to finding a subset of nums whose XOR sum is target, and maximizing the size of this subset.
    // Minimum removals = N - Maximum subset size.

    // Since N <= 40, we can use Meet-in-the-Middle (MITM).
    const n1 = Math.floor(n / 2);
    const n2 = n - n1;
    const nums1 = nums.slice(0, n1);
    const nums2 = nums.slice(n1);

    // 1. Generate all possible XOR sums for the first half (nums1) and store the size of the subset that generated it.
    // Map: xor_sum -> max_subset_size
    const map1 = new Map();

    // Iterate through all 2^n1 subsets of nums1
    for (let i = 0; i < (1 << n1); i++) {
        let currentXor = 0;
        let subsetSize = 0;
        for (let j = 0; j < n1; j++) {
            if ((i >> j) & 1) {
                currentXor ^= nums1[j];
                subsetSize++;
            }
        }

        if (!map1.has(currentXor) || subsetSize > map1.get(currentXor)) {
            map1.set(currentXor, subsetSize);
        }
    }

    // 2. Generate all possible XOR sums for the second half (nums2) and check against map1.
    let maxSubsetSize = -1;

    // Iterate through all 2^n2 subsets of nums2
    for (let i = 0; i < (1 << n2); i++) {
        let currentXor2 = 0;
        let subsetSize2 = 0;
        for (let j = 0; j < n2; j++) {
            if ((i >> j) & 1) {
                currentXor2 ^= nums2[j];
                subsetSize2++;
            }
        }

        // We need (Xor1 ^ Xor2) = target
        // Which means Xor1 = target ^ Xor2
        const requiredXor1 = target ^ currentXor2;

        if (map1.has(requiredXor1)) {
            const size1 = map1.get(requiredXor1);
            const totalSize = size1 + subsetSize2;

            if (totalSize > maxSubsetSize) {
                maxSubsetSize = totalSize;
            }
        }
    }

    if (maxSubsetSize === -1) {
        return -1;
    } else {
        // Minimum removals = Total length - Maximum kept elements
        return n - maxSubsetSize;
    }
}

