use std::collections::HashMap;

fn solve(nums: Vec<i64>, target: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return if target == 0 { 0 } else { -1 };
    }

    // The problem asks for the minimum number of removals such that the XOR sum of the remaining elements equals target.
    // This is equivalent to finding a subset of nums whose XOR sum is target, and maximizing the size of this subset.
    // Minimum removals = N - Maximum subset size.

    // Since N <= 40, we can use Meet-in-the-Middle (MITM).
    let n1 = n / 2;
    let n2 = n - n1;
    let nums1 = &nums[0..n1];
    let nums2 = &nums[n1..n];

    // 1. Generate all possible XOR sums for the first half (nums1) and store the maximum subset size that generated it.
    // Map: xor_sum -> max_subset_size
    let mut map1: HashMap<i64, usize> = HashMap::new();

    // Iterate through all 2^n1 subsets of nums1
    for i in 0..(1 << n1) {
        let mut current_xor = 0i64;
        let mut subset_size = 0;
        for j in 0..n1 {
            if (i >> j) & 1 == 1 {
                current_xor ^= nums1[j];
                subset_size += 1;
            }
        }

        // Store the maximum subset size found for this XOR sum
        map1.entry(current_xor)
            .and_modify(|e| *e = (*e).max(subset_size))
            .or_insert(subset_size);
    }

    // 2. Generate all possible XOR sums for the second half (nums2) and check against map1.
    let mut max_subset_size: Option<usize> = None;

    // Iterate through all 2^n2 subsets of nums2
    for i in 0..(1 << n2) {
        let mut current_xor2 = 0i64;
        let mut subset_size2 = 0;
        for j in 0..n2 {
            if (i >> j) & 1 == 1 {
                current_xor2 ^= nums2[j];
                subset_size2 += 1;
            }
        }

        // We need (Xor1 ^ Xor2) = target
        // Which means Xor1 = target ^ Xor2
        let required_xor1 = target ^ current_xor2;

        if let Some(&size1) = map1.get(&required_xor1) {
            let total_size = size1 + subset_size2;

            match max_subset_size {
                Some(current_max) => {
                    if total_size > current_max {
                        max_subset_size = Some(total_size);
                    }
                }
                None => {
                    max_subset_size = Some(total_size);
                }
            }
        }
    }

    match max_subset_size {
        Some(max_size) => (n - max_size) as i64,
        None => -1,
    }
}
